def validate_batch2_country_codes() -> None:
    """Validate WVS ISO3 formatting and batch-size expectations."""
    if len(BATCH2_WVS_ISO3) != 25:
        raise ValueError(f"batch2 must have 25 countries, got {len(BATCH2_WVS_ISO3)}")
    if len(set(BATCH2_WVS_ISO3)) != len(BATCH2_WVS_ISO3):
        raise ValueError("batch2 has duplicate ISO3 country codes")
    bad = [c for c in BATCH2_WVS_ISO3 if not (len(c) == 3 and c.isupper())]
    if bad:
        raise ValueError(f"batch2 invalid ISO3 format: {bad}")
    missing_lang = [c for c in BATCH2_WVS_ISO3 if c not in BATCH2_COUNTRY_LANG]
    if missing_lang:
        raise ValueError(f"batch2 missing language mapping for: {missing_lang}")


if __name__ == "__main__":
    validate_batch2_country_codes()
    print(f"Batch 2 descriptors: {len(BATCH2_DESCRIPTORS)} languages loaded")
